import java.util.Arrays;
import java.util.HashMap;
import java.util.Map;

public class Solution {

    /**
     * Generates a map where keys are possible XOR sums of subsets of arr,
     * and values are the maximum size of a subset that achieves that XOR sum.
     * @param arr The array segment.
     * @returns A map of {xor_sum: max_size}.
     */
    private static Map<Long, Integer> generateMap(long[] arr) {
        Map<Long, Integer> map = new HashMap<>();
        int M = arr.length;

        // Iterate through all 2^M subsets using a bitmask
        int limit = 1 << M;

        for (int i = 0; i < limit; i++) {
            long currentXor = 0;
            int currentSize = 0;

            for (int j = 0; j < M; j++) {
                // Check if the j-th element is included in the subset defined by i
                if (((i >> j) & 1) == 1) {
                    currentXor ^= arr[j];
                    currentSize++;
                }
            }

            // Update map: we only store the maximum size found for a given XOR sum
            map.put(currentXor, Math.max(map.getOrDefault(currentXor, -1), currentSize));
        }
        return map;
    }

    public static long solve(long[] nums, long target) {
        int N = nums.length;

        // Split the array into two halves for Meet-in-the-Middle
        int N1 = N / 2;
        long[] L = Arrays.copyOfRange(nums, 0, N1);
        long[] R = Arrays.copyOfRange(nums, N1, N);

        // Generate maps for both halves
        Map<Long, Integer> mapL = generateMap(L);
        Map<Long, Integer> mapR = generateMap(R);

        int maxSize = -1;

        // Combine results: Find max(sizeL + sizeR) such that xorL ^ xorR = target
        for (Map.Entry<Long, Integer> entryL : mapL.entrySet()) {
            long xorL = entryL.getKey();
            int sizeL = entryL.getValue();

            // Required xorR = target XOR xorL
            long requiredXorR = target ^ xorL;

            if (mapR.containsKey(requiredXorR)) {
                int sizeR = mapR.get(requiredXorR);
                int currentTotalSize = sizeL + sizeR;

                if (currentTotalSize > maxSize) {
                    maxSize = currentTotalSize;
                }
            }
        }

        if (maxSize == -1) {
            // No subset combination achieves the target
            return -1;
        } else {
            // Minimum removals = Total length - Maximum size of the desired subset
            return (long)N - maxSize;
        }
    }
}

